      "content": "const express = require('express');
const router = express.Router();
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', (req, res) => {
  const { userId, role } = req.body;

  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'User ID and role are required.');
  }

  const member = membersService.createMember(req.projectId, userId, role);

  if (member.error) {
    return sendError(res, member.status, member.code, member.message);
  }

  res.status(201).json({ member });
});

module.exports = router;
