      "content": "const express = require('express');
const router = express.Router();
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', (req, res) => {
  const { message } = req.body;

  if (!message) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Message is required.');
  }

  const comment = commentsService.createComment(req.projectId, req.taskId, message);

  if (comment.error) {
    return sendError(res, comment.status, comment.code, comment.message);
  }

  res.status(201).json({ comment });
});

module.exports = router;
